+            a,
+            b,
+            scale: 0.05,
+            dim,
+            rank,
+        }
+    }
+
+    #[inline]
+    pub fn apply(&self, input: &[f32], output: &mut [f32]) {
+        output.copy_from_slice(input);
+
+        let mut hidden = vec![0.0f32; self.rank];
+        for r in 0..self.rank {
