+                hidden[r] += self.a[i * self.rank + r] * input[i];
+            }
+        }
+
+        for i in 0..self.dim {
+            let mut delta = 0.0f32;
+            for r in 0..self.rank {
+                delta += self.b[r * self.dim + i] * hidden[r];
+            }
+            output[i] += self.scale * delta;
+        }
+    }
+}
