+    println!("Gate Decision:");
+    println!("  Allowed: {}", decision.allow);
+    println!(
+        "  Compute Lane: {:?} ({})",
+        decision.lane,
+        lane_description(decision.lane)
+    );
+    if let Some(reason) = &decision.reason {
+        println!("  Reason: {}", reason);
