+
+        let a = vec![1.0, 0.0, 0.0, 0.0];
+        let b = vec![1.0, 0.0, 0.0, 0.0];
+        let c = vec![-1.0, 0.0, 0.0, 0.0];
+
+        assert!((adapter.cosine_similarity(&a, &b) - 1.0).abs() < 0.01);
+        assert!((adapter.cosine_similarity(&a, &c) + 1.0).abs() < 0.01);
+    }
+}

