+        let context = vec![0.1f32; 8];
+
+        let routings: Vec<ExpertRouting> = inputs.iter().map(|inp| moe.route(inp, &context)).collect();
+
+        let usage = moe.expert_usage(&routings);
+
+        assert_eq!(usage.len(), 4);
+        // Should sum to approximately 1
