+        for (edge_id, edge_energy) in edge_energies {
+            let scope_id = scope_mapping
+                .get(edge_id)
+                .cloned()
+                .unwrap_or_else(|| "default".to_string());
+
+            scope_groups
+                .entry(scope_id)
+                .or_default()
+                .push(edge_energy);
+        }
+
+        // Create scope energies
+        scope_groups
+            .into_iter()
+            .map(|(scope_id, edges)| {
+                let scope_energy = ScopeEnergy::from_edges(&scope_id, &edges);
+                (scope_id, scope_energy)
+            })
+            .collect()
+    }
+}
